import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Sources","description":"","frontmatter":{},"headers":[],"relativePath":"guide/sources.md","filePath":"guide/sources.md"}'),s={name:"guide/sources.md"};function i(n,t,o,l,c,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h1><p>InspoSearch queries <strong>~2,400 sources</strong> across eight categories. The count is split between:</p><ul><li><strong>~180 static adapters</strong> hand-written in <a href="https://github.com/GI-Synth/InspoSearch/blob/main/src/fetchers.js" target="_blank" rel="noreferrer"><code>src/fetchers.js</code></a> and community manifests in <a href="https://github.com/GI-Synth/InspoSearch/tree/main/insposearch/sources" target="_blank" rel="noreferrer"><code>insposearch/sources/*.json</code></a></li><li><strong>~2,300 dynamic providers</strong> discovered at runtime from Europeana&#39;s <code>DATA_PROVIDER</code> facets (~2,250) and DPLA hubs (~50)</li></ul><p>Dynamic discovery requires the Europeana / DPLA keys — see <a href="/docs/guide/api-keys">API Keys</a>. Without them, you still get the static set and anonymous APIs.</p><h2 id="the-eight-categories" tabindex="-1">The eight categories <a class="header-anchor" href="#the-eight-categories" aria-label="Permalink to &quot;The eight categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>What&#39;s in it</th></tr></thead><tbody><tr><td><strong>Museums</strong></td><td>Major and regional museums — painting, sculpture, decorative arts, ethnographic collections</td></tr><tr><td><strong>Historical</strong></td><td>National libraries, archives, digital heritage aggregators (Europeana, DPLA, Trove, Gallica, LoC)</td></tr><tr><td><strong>Art and Design</strong></td><td>Illustration archives, design collections, typography, poster archives</td></tr><tr><td><strong>Photography</strong></td><td>Press archives, photo agencies, stock providers, historic photography</td></tr><tr><td><strong>Nature</strong></td><td>Natural history museums, botanical illustration, biodiversity atlases</td></tr><tr><td><strong>Maps</strong></td><td>Cartographic collections, historical atlases, map libraries</td></tr><tr><td><strong>Fashion</strong></td><td>Costume archives, textile design, fashion photography</td></tr><tr><td><strong>Science</strong></td><td>Scientific illustration, medical archives, astronomy, technical drawings</td></tr></tbody></table><p>Toggle entire categories or individual sources from the source filter sidebar (<code>s</code>).</p><h2 id="highlighted-static-sources" tabindex="-1">Highlighted static sources <a class="header-anchor" href="#highlighted-static-sources" aria-label="Permalink to &quot;Highlighted static sources&quot;">​</a></h2><p>This is a representative selection, not the full list. The definitive list is in the source filter sidebar in the app.</p><h3 id="museums" tabindex="-1">Museums <a class="header-anchor" href="#museums" aria-label="Permalink to &quot;Museums&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>API style</th><th style="text-align:center;">Key?</th></tr></thead><tbody><tr><td>The Metropolitan Museum of Art</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Rijksmuseum</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Victoria and Albert Museum</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Art Institute of Chicago</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Cleveland Museum of Art</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Walters Art Museum</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Harvard Art Museums</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Cooper Hewitt, Smithsonian</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>National Gallery of Art (US)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Los Angeles County Museum of Art</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Brooklyn Museum</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Yale University Art Gallery</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Philadelphia Museum of Art</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Musée du Louvre</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Museo del Prado</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Uffizi</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>National Gallery (London)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>State Hermitage Museum</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Kunsthistorisches Museum Vienna</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Museum Digital (DE / NAT / SMB)</td><td>REST</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="historical-archives" tabindex="-1">Historical / Archives <a class="header-anchor" href="#historical-archives" aria-label="Permalink to &quot;Historical / Archives&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>API style</th><th style="text-align:center;">Key?</th></tr></thead><tbody><tr><td>Europeana</td><td>REST</td><td style="text-align:center;">✓ (unlocks ~2,000 sub-providers)</td></tr><tr><td>Digital Public Library of America</td><td>REST</td><td style="text-align:center;">✓ (unlocks DPLA hubs)</td></tr><tr><td>Library of Congress</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Smithsonian Open Access</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Internet Archive</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>National Archives (NARA)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Biodiversity Heritage Library</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>David Rumsey Map Collection</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Wellcome Collection</td><td>REST / IIIF</td><td style="text-align:center;">—</td></tr><tr><td>British Library</td><td>IIIF</td><td style="text-align:center;">—</td></tr><tr><td>Gallica (BnF)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>National Library of Australia (Trove)</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>National Diet Library (Japan)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Bodleian Libraries (Oxford)</td><td>IIIF</td><td style="text-align:center;">—</td></tr><tr><td>Cambridge Digital Library</td><td>IIIF</td><td style="text-align:center;">—</td></tr><tr><td>Digital Commonwealth</td><td>IIIF</td><td style="text-align:center;">—</td></tr><tr><td>Bayerische Staatsbibliothek</td><td>IIIF</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="photography" tabindex="-1">Photography <a class="header-anchor" href="#photography" aria-label="Permalink to &quot;Photography&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>API style</th><th style="text-align:center;">Key?</th></tr></thead><tbody><tr><td>Unsplash</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Flickr Commons</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Pexels</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Pixabay</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>rawpixel</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Library of Congress Prints &amp; Photographs</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>George Eastman Museum</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Sketchfab Heritage</td><td>REST</td><td style="text-align:center;">—</td></tr></tbody></table><h3 id="art-and-design" tabindex="-1">Art and Design <a class="header-anchor" href="#art-and-design" aria-label="Permalink to &quot;Art and Design&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>API style</th><th style="text-align:center;">Key?</th></tr></thead><tbody><tr><td>Wikimedia Commons</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Artvee</td><td>Scrape</td><td style="text-align:center;">—</td></tr><tr><td>Cooper Hewitt (Design)</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Noun Project</td><td>REST</td><td style="text-align:center;">✓</td></tr><tr><td>Open Clip Art</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Creative Commons Search</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Behance</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Giphy</td><td>REST</td><td style="text-align:center;">✓</td></tr></tbody></table><h3 id="nature" tabindex="-1">Nature <a class="header-anchor" href="#nature" aria-label="Permalink to &quot;Nature&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source</th><th>API style</th><th style="text-align:center;">Key?</th></tr></thead><tbody><tr><td>Biodiversity Heritage Library</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Natural History Museum (London)</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>Smithsonian National Museum of Natural History</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>New York Botanical Garden</td><td>REST</td><td style="text-align:center;">—</td></tr><tr><td>iNaturalist</td><td>REST</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="api-styles-explained" tabindex="-1">API styles, explained <a class="header-anchor" href="#api-styles-explained" aria-label="Permalink to &quot;API styles, explained&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Style</th><th>What it means</th><th>Examples</th></tr></thead><tbody><tr><td><strong>REST</strong></td><td>Standard HTTP + JSON</td><td>Met, Unsplash, Europeana</td></tr><tr><td><strong>IIIF</strong></td><td><a href="https://iiif.io" target="_blank" rel="noreferrer">International Image Interoperability Framework</a> — standardised image / manifest APIs</td><td>British Library, Bodleian, Wellcome</td></tr><tr><td><strong>Scrape</strong></td><td>HTML scraping (no official API)</td><td>Artvee</td></tr></tbody></table><p>IIIF sources automatically get deep-zoom support via OpenSeadragon. REST sources get deep-zoom only if they serve IIIF image tiles on the side.</p><h2 id="cors-blocked-sources" tabindex="-1">CORS-blocked sources <a class="header-anchor" href="#cors-blocked-sources" aria-label="Permalink to &quot;CORS-blocked sources&quot;">​</a></h2><p>A handful of APIs don&#39;t allow browser-to-server calls and can&#39;t be queried client-side. These are fetched nightly by <a href="https://github.com/GI-Synth/InspoSearch/blob/main/.github/workflows/nightly-fetch.yml" target="_blank" rel="noreferrer">a GitHub Actions job</a> and served from pre-computed JSON in <a href="https://github.com/GI-Synth/InspoSearch/tree/main/insposearch/data" target="_blank" rel="noreferrer"><code>insposearch/data/</code></a>. The source sidebar treats them identically to live ones.</p><h2 id="missing-a-source-add-it" tabindex="-1">Missing a source? Add it <a class="header-anchor" href="#missing-a-source-add-it" aria-label="Permalink to &quot;Missing a source? Add it&quot;">​</a></h2><p>If there&#39;s a public image API you want to see in InspoSearch, adding it is usually a single JSON manifest plus an optional adapter function.</p><p>See <a href="/docs/guide/adding-a-source">Adding a Source</a> for the schema, the 3-term test protocol, and the PR checklist.</p>',27)])])}const y=e(s,[["render",i]]);export{u as __pageData,y as default};
